# Mock legal system check for adequate legal representation advice
def check_legal_representation_advice(accused_represented, judicial_officer_advised, claim_of_right):
    if not judicial_officer_advised and not accused_represented:
        if claim_of_right:
            return "Failure of justice: Omission led to unarticulated defense."
        else:
            return "No failure of justice: No prejudice despite omission."
    elif accused_represented:
        return "No irregularity: Accused had legal representation."
    else:
        return "No failure of justice: Irrelevant omission."

# Example usage
result = check_legal_representation_advice(
    accused_represented=False,
    judicial_officer_advised=False,
    claim_of_right=True
)
print(result)  # Output: Failure of justice: Omission led to unarticulated defense.
